mapper.select:
SELECT id, patient_id, department_id, queue_number, status,
       queued_at, called_at, completed_at
FROM waiting_queue
WHERE department_id = #{departmentId}
  AND status = #{status}
ORDER BY queue_number ASC

mapper.update:
UPDATE waiting_queue
SET status = #{status}
    , called_at = #{calledAt}
    , completed_at = #{completedAt}
WHERE id = #{id}
